/* Override libcrypto's CRYPTO_new_ex_data with a lock-free version.
   Use parentheses to prevent AmiSSL macro expansion. */
int (CRYPTO_new_ex_data)(int class_index, void *obj, CRYPTO_EX_DATA *ad)
{
    if (ad != NULL) {
        ad->ctx = NULL;
        ad->sk = NULL;
    }
    return 1;
}

/* Override CRYPTO_free_ex_data similarly. */
void (CRYPTO_free_ex_data)(int class_index, void *obj, CRYPTO_EX_DATA *ad)
{
}

