/* Use AllocVec/FreeVec directly instead of malloc/free to avoid
   dependencies on CRT/libcmt initialization (which may not run
   with -nostartfiles). AllocVec is provided by exec.library which
   is always available. */
void *(CRYPTO_malloc)(size_t num, const char *file, int line)
{
    void *p;
    (void)file; (void)line;
    p = AllocVec(num, MEMF_ANY);
    if (p == NULL && num > 0)
        p = malloc(num);
    return p;
}

/* Also override CRYPTO_free and CRYPTO_zalloc similarly */
extern void *(realloc)(void *ptr, size_t size);

void (CRYPTO_free)(void *ptr, const char *file, int line)
{
    (void)file; (void)line;
    FreeVec(ptr);
}

void *(CRYPTO_zalloc)(size_t num, const char *file, int line)
{
    void *p = (CRYPTO_malloc)(num, file, line);
    if (p != NULL && num > 0) {
        memset(p, 0, num);
    } else if (p == NULL && num > 0) {
        /* AllocVec may fail for very small sizes on some AROS builds.
           Fall back to calloc as a workaround. */
        p = calloc(1, num);
    }
    return p;
}

/* CRYPTO_aligned_alloc - return NULL to force OpenSSL to use plain malloc.
   The default implementation calls through function pointer tables that may
   not work correctly on AROS with our memory override stubs. */
void *(CRYPTO_aligned_alloc)(size_t num, size_t alignment, void **freeptr,
                             const char *file, int line)
{
    (void)num; (void)alignment; (void)file; (void)line;
    *freeptr = NULL;
    return NULL;
}

void *(CRYPTO_calloc)(size_t num, size_t size, const char *file, int line)
{
    size_t bytes = num * size;
    /* Check for overflow */
    if (num != 0 && bytes / num != size) return NULL;
    return (CRYPTO_zalloc)(bytes, file, line);
}

void *(CRYPTO_realloc)(void *addr, size_t num, const char *file, int line)
{
    (void)file; (void)line;
    return (realloc)(addr, num);
}

